VALUES
  ('public-health-specialist-moex-01107', 'public-health-specialist', 'public-health-specialist-moex-114-aaf759af', 'sub-public-health-specialist-02', NULL, 'single_choice', '關於流行病學研究中「因果關係」與「相關性」的敘述，下列何者錯誤？', '["若研究設計嚴謹且執行得當之下，未觀察到暴露與疾病的相關性，則可推論兩者無因果關係", "若理論上暴露與疾病並無因果關係，但研究中觀察到相關性，必定是研究中有偏差", "若理論上暴露與疾病應有因果關係，但研究中未觀察到相關性，可能是研究設計有缺陷", "只要觀察到暴露與疾病有相關性，即可直接推論兩者存在因果關係"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:57+00:00", "source_pdf_sha1": "5aad29b928bd", "answer_pdf_sha1": "36cab4a52ac0", "source_family": "moex-gov-tw", "moex": {"exam_code": "114100", "c": "108", "s": "0803", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "流行病學", "year": "114", "exam_name": "114年第二次專技人員高等考試營養師、護理師、社會工作師考試、114年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 11, "answer_corrected": false, "flags": [], "slug": "publichealth", "db_exam_id": "public-health-specialist"}'::jsonb, NULL),
  ('public-health-specialist-moex-01108', 'public-health-specialist', 'public-health-specialist-moex-114-aaf759af', 'sub-public-health-specialist-02', NULL, 'single_choice', '若只有特定出生世代的疾病率有一致增加的情形，但是不同出生世代的年齡別的疾病率未隨 年齡的增加而增加，請問此疾病率受到何效應影響？', '["年齡（age）效應", "年代（period）效應", "世代（cohort）效應", "年齡（age）與世代（cohort）效應"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:57+00:00", "source_pdf_sha1": "5aad29b928bd", "answer_pdf_sha1": "36cab4a52ac0", "source_family": "moex-gov-tw", "moex": {"exam_code": "114100", "c": "108", "s": "0803", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "流行病學", "year": "114", "exam_name": "114年第二次專技人員高等考試營養師、護理師、社會工作師考試、114年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 12, "answer_corrected": false, "flags": [], "slug": "publichealth", "db_exam_id": "public-health-specialist"}'::jsonb, NULL),
  ('public-health-specialist-moex-01109', 'public-health-specialist', 'public-health-specialist-moex-114-aaf759af', 'sub-public-health-specialist-02', NULL, 'single_choice', '在世代研究中，若疾病診斷工具的測量誤差程度在不同暴露組別間有異，可能會導致何種類 型的錯誤分組？', '["無差異性的錯誤分組（Non-differentialmisclassification）", "有差異性的錯誤分組（Differentialmisclassification）", "隨機分組錯誤（Randommisclassification）", "完全正確的分組（Perfectclassification）"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:57+00:00", "source_pdf_sha1": "5aad29b928bd", "answer_pdf_sha1": "36cab4a52ac0", "source_family": "moex-gov-tw", "moex": {"exam_code": "114100", "c": "108", "s": "0803", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "流行病學", "year": "114", "exam_name": "114年第二次專技人員高等考試營養師、護理師、社會工作師考試、114年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 13, "answer_corrected": false, "flags": [], "slug": "publichealth", "db_exam_id": "public-health-specialist"}'::jsonb, NULL),
  ('public-health-specialist-moex-01110', 'public-health-specialist', 'public-health-specialist-moex-114-aaf759af', 'sub-public-health-specialist-02', NULL, 'single_choice', '生態相關研究因為在團體層次上觀察到暴露和疾病的存在相關，但這樣的相關未必出現在個 人層次，這是何種問題造成？', '["生態誤謬（ecologicfallacy）", "反向因果關係（reversecausality）", "選擇偏差（selectionbias）", "存活偏差（survivalbias）"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:57+00:00", "source_pdf_sha1": "5aad29b928bd", "answer_pdf_sha1": "36cab4a52ac0", "source_family": "moex-gov-tw", "moex": {"exam_code": "114100", "c": "108", "s": "0803", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "流行病學", "year": "114", "exam_name": "114年第二次專技人員高等考試營養師、護理師、社會工作師考試、114年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 14, "answer_corrected": false, "flags": [], "slug": "publichealth", "db_exam_id": "public-health-specialist"}'::jsonb, NULL),
  ('public-health-specialist-moex-01111', 'public-health-specialist', 'public-health-specialist-moex-114-aaf759af', 'sub-public-health-specialist-02', NULL, 'single_choice', '回溯式世代研究的主要優勢是什麼？', '["能夠完全避免追蹤遺失的問題", "所需的研究資源和時間較前瞻性世代研究少", "能夠直接控制所有干擾因子的影響", "不需要依賴現有的資料系統"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:57+00:00", "source_pdf_sha1": "5aad29b928bd", "answer_pdf_sha1": "36cab4a52ac0", "source_family": "moex-gov-tw", "moex": {"exam_code": "114100", "c": "108", "s": "0803", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "流行病學", "year": "114", "exam_name": "114年第二次專技人員高等考試營養師、護理師、社會工作師考試、114年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 15, "answer_corrected": false, "flags": [], "slug": "publichealth", "db_exam_id": "public-health-specialist"}'::jsonb, NULL),
  ('public-health-specialist-moex-01112', 'public-health-specialist', 'public-health-specialist-moex-114-aaf759af', 'sub-public-health-specialist-02', NULL, 'single_choice', '下列研究設計何者可以估計疾病和暴露的盛行率但可能有反向因果關係（reverse causality） 的偏差？', '["生態相關研究（ecologicstudies）", "橫斷研究（cross-sectionalstudies）", "病例對照研究（case-controlstudies）", "世代研究（cohortstudies）"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:57+00:00", "source_pdf_sha1": "5aad29b928bd", "answer_pdf_sha1": "36cab4a52ac0", "source_family": "moex-gov-tw", "moex": {"exam_code": "114100", "c": "108", "s": "0803", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "流行病學", "year": "114", "exam_name": "114年第二次專技人員高等考試營養師、護理師、社會工作師考試、114年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 16, "answer_corrected": false, "flags": [], "slug": "publichealth", "db_exam_id": "public-health-specialist"}'::jsonb, NULL),
  ('public-health-specialist-moex-01113', 'public-health-specialist', 'public-health-specialist-moex-114-aaf759af', 'sub-public-health-specialist-02', NULL, 'single_choice', '某疾病療法試驗中，安慰劑控制組的 5 年累積死亡率為 10%，介入治療組為 5%。據此可估 計若能預防1例在5年內死亡需要治療多少人？', '["5人", "10人", "15人", "20人"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:57+00:00", "source_pdf_sha1": "5aad29b928bd", "answer_pdf_sha1": "36cab4a52ac0", "source_family": "moex-gov-tw", "moex": {"exam_code": "114100", "c": "108", "s": "0803", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "流行病學", "year": "114", "exam_name": "114年第二次專技人員高等考試營養師、護理師、社會工作師考試、114年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 17, "answer_corrected": false, "flags": [], "slug": "publichealth", "db_exam_id": "public-health-specialist"}'::jsonb, NULL),
  ('public-health-specialist-moex-01114', 'public-health-specialist', 'public-health-specialist-moex-114-aaf759af', 'sub-public-health-specialist-02', NULL, 'single_choice', '研究團隊欲測試學名藥與原廠藥「效果相當」，且學名藥成本僅一半。此研究設計應優先考慮？', '["檢定學名藥是否「優於」原廠藥（優越性試驗）", "檢定學名藥是否「不劣於」原廠藥（非劣性試驗）", "增加樣本數以降低型I錯誤", "改用觀察性研究設計"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:57+00:00", "source_pdf_sha1": "5aad29b928bd", "answer_pdf_sha1": "36cab4a52ac0", "source_family": "moex-gov-tw", "moex": {"exam_code": "114100", "c": "108", "s": "0803", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "流行病學", "year": "114", "exam_name": "114年第二次專技人員高等考試營養師、護理師、社會工作師考試、114年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 18, "answer_corrected": false, "flags": [], "slug": "publichealth", "db_exam_id": "public-health-specialist"}'::jsonb, NULL),
  ('public-health-specialist-moex-01115', 'public-health-specialist', 'public-health-specialist-moex-114-aaf759af', 'sub-public-health-specialist-02', NULL, 'single_choice', '關於世代研究（cohortstudies）下列何者錯誤？', '["研究個案拒絕參加研究，不回應或失聯（loss to follow-up）者，若其危險因子暴露特質或 疾病嚴重度和願意參加且定期被追蹤的個案有差異，將產生選擇性偏差（selectionbiases）", "世代研究適合探討常見暴露、罕見疾病", "前瞻性世代研究（Prospectivecohortstudies）較容易建立暴露和疾病間的因果時序性", "以一個定義族群起始的前瞻性世代研究可以同時探討多種暴露對疾病的影響"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:57+00:00", "source_pdf_sha1": "5aad29b928bd", "answer_pdf_sha1": "36cab4a52ac0", "source_family": "moex-gov-tw", "moex": {"exam_code": "114100", "c": "108", "s": "0803", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "流行病學", "year": "114", "exam_name": "114年第二次專技人員高等考試營養師、護理師、社會工作師考試、114年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 19, "answer_corrected": false, "flags": [], "slug": "publichealth", "db_exam_id": "public-health-specialist"}'::jsonb, NULL),
  ('public-health-specialist-moex-01116', 'public-health-specialist', 'public-health-specialist-moex-114-aaf759af', 'sub-public-health-specialist-02', NULL, 'single_choice', '關於世代研究（cohortstudies）下列何者錯誤？', '["可以直接估算：發生率、相對危險性（relativerisk,RR）、可歸因危險性（attributablerisk,AR）", "RR是相關強度的指標，用於病因探討；AR常用於評估減少有害暴露的公共衛生計畫能預 防多少疾病", "RR=1指出暴露和疾病無相關（noassociation）", "探討某一疾病歸因於某一暴露的風險時，當暴露組的可歸因風險百分比很高，則族群可歸 因風險的百分比也很高"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:57+00:00", "source_pdf_sha1": "5aad29b928bd", "answer_pdf_sha1": "36cab4a52ac0", "source_family": "moex-gov-tw", "moex": {"exam_code": "114100", "c": "108", "s": "0803", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "流行病學", "year": "114", "exam_name": "114年第二次專技人員高等考試營養師、護理師、社會工作師考試、114年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 20, "answer_corrected": false, "flags": [], "slug": "publichealth", "db_exam_id": "public-health-specialist"}'::jsonb, NULL)
